const items = $json.items || [];
const prop = items.find((i) => i.kind === 'skill_improvement_proposal');
if (!prop || !prop.proposal_id) {
  throw new Error('No proposal_id in remember/entry response: ' + JSON.stringify($json));
}
return [{ json: { proposal_id: prop.proposal_id, skill_name: prop.skill_name } }];

const p = $json;
const before = (p.old_procedure || '').split('\n');
const after = (p.proposed_procedure || '').split('\n');
const n = before.length, m = after.length;
const dp = Array.from({ length: n + 1 }, () => new Array(m + 1).fill(0));
for (let i = n - 1; i >= 0; i--) {
  for (let j = m - 1; j >= 0; j--) {
    dp[i][j] = before[i] === after[j] ? dp[i + 1][j + 1] + 1 : Math.max(dp[i + 1][j], dp[i][j + 1]);
  }
}
const out = [];
let i = 0, j = 0;
while (i < n && j < m) {
  if (before[i] === after[j]) { out.push('  ' + before[i]); i++; j++; }
  else if (dp[i + 1][j] >= dp[i][j + 1]) { out.push('- ' + before[i]); i++; }
  else { out.push('+ ' + after[j]); j++; }
}
while (i < n) out.push('- ' + before[i++]);
while (j < m) out.push('+ ' + after[j++]);
const diff = out.join('\n');
const md = [
  `## Skill Delta proposal: ${p.skill_name}`, '',
  `Proposal: ${p.proposal_id}`,
  `Confidence: ${p.confidence}`,
  `Rationale: ${p.rationale}`, '',
  '```diff', diff, '```',
].join('\n');
return [{ json: {
  proposal_id: p.proposal_id, skill_id: p.skill_id, skill_name: p.skill_name,
  confidence: p.confidence, rationale: p.rationale,
  old_procedure: p.old_procedure, proposed_procedure: p.proposed_procedure,
  skill_delta: diff, skill_delta_markdown: md,
  approved: $('Demo Controls').item.json.approved,
} }];

const packet = $('Build Review Packet').item.json;
const updated = ($json && $json.procedure) || '';
return [{ json: {
  status: 'completed',
  skill_to_improve: packet.skill_name,
  proposal_id: packet.proposal_id,
  applied: true,
  confidence: packet.confidence,
  rationale: packet.rationale,
  skill_delta: packet.skill_delta,
  skill_delta_markdown: packet.skill_delta_markdown,
  updated_procedure: updated,
} }];

return [{ json: {
  status: 'waiting_for_review',
  proposal_id: $('Build Review Packet').item.json.proposal_id,
  skill_delta_markdown: $('Build Review Packet').item.json.skill_delta_markdown,
  message: 'Proposal created and the before/after diff is ready, but it was not approved. Replace the Demo Controls approved flag with a Slack/Wait approval to gate this in production.',
} }];

return [{ json: {
  status: 'no_improvement_needed',
  eval_score: $('Demo Controls').item.json.eval_score,
  score_threshold: $('Demo Controls').item.json.score_threshold,
  message: 'Score met or exceeded the threshold, so no skill-improvement proposal was requested.',
} }];
